    the case of the first item in that group of values. For example, if
    a list of users has cities ``["CA", "NY", "ca"]``, the "CA" and "ca"
    entries will be grouped together, under the key "CA".

    .. sourcecode:: jinja

        <ul>{% for city, items in users|groupby("city", case_sensitive=true) %}
          <li>{{ city }}: {{ items|map(attribute="name")|join(", ") }}</li>
        {% endfor %}</ul>

    You can pass ``with_counts=True`` to also get the number of items in
    each group without a separate ``|list|length`` call. ``groupby`` then
    yields ``(grouper, list, count)`` tuples.

    .. sourcecode:: jinja

        <ul>{% for city, items, count in users|groupby("city", with_counts=True) %}
          <li>{{ city }} ({{ count }})</li>
        {% endfor %}</ul>

    .. versionchanged:: 3.1
        Added the ``case_sensitive`` and ``with_counts`` parameters.

    .. versionchanged:: 3.0
        Added the ``default`` parameter.

    .. versionchanged:: 2.6
        The attribute supports dot notation for nested access.
    """
    return _group_tuples(
        environment, value, attribute, default, case_sensitive, with_counts
    )


@async_variant(sync_do_groupby)  # type: ignore
async def do_groupby(
    environment: "Environment",
    value: "t.Union[t.AsyncIterable[V], t.Iterable[V]]",
    attribute: t.Union[str, int],
